/**
 * n8n Code Node: Prepare Artifact Upload Package
 *
 * Purpose:
 * This node collects the generated text outputs from the previous AI nodes,
 * cleans them where necessary, creates a run-specific blob folder name,
 * and prepares one binary item per artifact for upload to Azure Blob Storage.
 *
 * Result:
 * Each returned item represents one file:
 * - json.blobPath = target path in Azure Blob Storage
 * - json.fileName = file name
 * - binary.data  = file content as binary data
 */

/**
 * Reads the text output from a previous n8n AI node.
 *
 * The OpenAI "Message a model" nodes return generated text here:
 * output[0].content[0].text
 *
 * If a node name is wrong or the output is empty, this returns an empty string.
 */
function getTextFromAiNode(nodeName) {
  const nodeJson = $(nodeName).first().json;

  return nodeJson.output?.[0]?.content?.[0]?.text ?? '';
}

/**
 * Removes Markdown code fences from generated artifacts.
 *
 * Example:
 * ```powershell
 * Write-Host "Hello"
 * ```
 *
 * becomes:
 * Write-Host "Hello"
 *
 * This is important because .ps1 and .csv files must not contain Markdown fences.
 */
function stripMarkdownCodeFence(text) {
  if (!text) {
    return '';
  }

  return text
    .replace(/^```powershell\s*/i, '')
    .replace(/^```ps1\s*/i, '')
    .replace(/^```markdown\s*/i, '')
    .replace(/^```csv\s*/i, '')
    .replace(/```$/i, '')
    .trim();
}

/**
 * Converts a string into a safe folder-name part.
 *
 * Example:
 * "Entra ID User Onboarding!" becomes "entra-id-user-onboarding"
 */
function slugify(value) {
  return String(value || '')
    .toLowerCase()
    .trim()
    .replace(/[^a-z0-9]+/g, '-')
    .replace(/^-+|-+$/g, '')
    .substring(0, 80);
}

/**
 * Returns today's date in ISO format: YYYY-MM-DD
 */
function getTodayAsIsoDate() {
  return new Date().toISOString().slice(0, 10);
}

/**
 * Very simple CSV parser for our generated CSV template.
 *
 * This is enough for our current generated template because it does not contain
 * commas inside quoted values.
 *
 * For production CSV parsing, use a proper CSV parser instead.
 */
function getFirstNameFromCsv(csvText) {
  if (!csvText || typeof csvText !== 'string') {
    return 'unknown';
  }

  const lines = csvText.trim().split(/\r?\n/).filter(Boolean);

  // We need at least a header row and one data row.
  if (lines.length < 2) {
    return 'unknown';
  }

  const headers = lines[0].split(',').map(header => header.trim());
  const firstRow = lines[1].split(',').map(value => value.trim());

  // Prefer the GivenName column if it exists.
  const givenNameIndex = headers.findIndex(header => header.toLowerCase() === 'givenname');

  if (givenNameIndex >= 0 && firstRow[givenNameIndex]) {
    return firstRow[givenNameIndex];
  }

  // Fallback: use the first word from DisplayName.
  const displayNameIndex = headers.findIndex(header => header.toLowerCase() === 'displayname');

  if (displayNameIndex >= 0 && firstRow[displayNameIndex]) {
    return firstRow[displayNameIndex].split(/\s+/)[0];
  }

  return 'unknown';
}

/**
 * Creates n8n binary data from text content.
 *
 * Azure Blob upload nodes normally expect binary data.
 * We convert the text content into base64 and attach file metadata.
 */
function createBinaryData(content, fileName, mimeType) {
  return {
    data: Buffer.from(content, 'utf8').toString('base64'),
    fileName: fileName,
    mimeType: mimeType,
  };
}

/**
 * Read all generated outputs from the existing workflow nodes.
 *
 * IMPORTANT:
 * The node names below must match your n8n node names exactly.
 * If one node has a different name, adjust it here.
 */
const requirementSpecification = getTextFromAiNode('AI - Requirement Structuring').trim();

const initialPowerShellScript = stripMarkdownCodeFence(
  getTextFromAiNode('AI - Create Powershell Script')
);

const riskReview = getTextFromAiNode('AI - Script Review').trim();

const improvedPowerShellScript = stripMarkdownCodeFence(
  getTextFromAiNode('AI - Script Improvement')
);

const readme = getTextFromAiNode('AI - Documentation Generation').trim();

const csvTemplate = stripMarkdownCodeFence(
  getTextFromAiNode('AI - CSV Template Generation')
);

const testChecklist = getTextFromAiNode('AI - Test Checklist Generation').trim();

const promptLibrary = getTextFromAiNode('AI - Prompt Library Summary').trim();

/**
 * Build the run folder name.
 *
 * Desired pattern:
 * date_purpose_firstname
 *
 * Example:
 * 2026-06-03_entra-user-onboarding_test
 */
const datePart = getTodayAsIsoDate();
const purposePart = slugify('entra-user-onboarding');
const firstNamePart = slugify(getFirstNameFromCsv(csvTemplate));

const runFolder = `${datePart}_${purposePart}_${firstNamePart}`;

/**
 * Create a final run summary.
 *
 * This file helps technicians understand what was generated
 * and how they should use the artifact package.
 */
const runSummary = `# Run Summary - AI-Assisted Entra ID User Onboarding Workflow

## Run Folder

\`${runFolder}\`

## Generated Artifacts

- requirement-specification.md
- Create-EntraUsers.ps1
- risk-review.md
- Create-EntraUsers-v2.ps1
- README.md
- users-template.csv
- test-checklist.md
- prompt-library.md
- run-summary.md

## Workflow Purpose

This artifact package was generated by an n8n-based AI-assisted workflow.

The workflow supports Azure consultants by generating, reviewing, improving, and documenting PowerShell artifacts for Microsoft Entra ID user onboarding from CSV files.

## Safety Statement

The generated files are engineering artifacts for human review.

n8n does not execute PowerShell.
n8n does not create users in Microsoft Entra ID.
A human Azure engineer must review and test the artifacts in a non-production environment before any real use.

## Recommended Technician Usage

1. Open README.md.
2. Review risk-review.md.
3. Inspect Create-EntraUsers-v2.ps1.
4. Use users-template.csv as the input structure.
5. Follow test-checklist.md in a non-production environment.
6. Execute manually only after human approval.

## Run Metadata

- Date: ${datePart}
- Purpose: Entra ID user onboarding
- First CSV example first name: ${firstNamePart}
`;

/**
 * Define all artifacts we want to upload.
 *
 * Each object becomes one file in Azure Blob Storage.
 */
const artifacts = [
  {
    fileName: 'requirement-specification.md',
    content: requirementSpecification,
    mimeType: 'text/markdown',
  },
  {
    fileName: 'Create-EntraUsers.ps1',
    content: initialPowerShellScript,
    mimeType: 'text/plain',
  },
  {
    fileName: 'risk-review.md',
    content: riskReview,
    mimeType: 'text/markdown',
  },
  {
    fileName: 'Create-EntraUsers-v2.ps1',
    content: improvedPowerShellScript,
    mimeType: 'text/plain',
  },
  {
    fileName: 'README.md',
    content: readme,
    mimeType: 'text/markdown',
  },
  {
    fileName: 'users-template.csv',
    content: csvTemplate,
    mimeType: 'text/csv',
  },
  {
    fileName: 'test-checklist.md',
    content: testChecklist,
    mimeType: 'text/markdown',
  },
  {
    fileName: 'prompt-library.md',
    content: promptLibrary,
    mimeType: 'text/markdown',
  },
  {
    fileName: 'run-summary.md',
    content: runSummary,
    mimeType: 'text/markdown',
  },
];

/**
 * Return one n8n item per artifact.
 *
 * The Azure Blob Storage node will process each item and upload it as one blob.
 */
return artifacts.map(artifact => {
  const blobPath = `${runFolder}/${artifact.fileName}`;

  return {
    json: {
      runFolder: runFolder,
      fileName: artifact.fileName,
      blobPath: blobPath,
      mimeType: artifact.mimeType,
    },
    binary: {
      data: createBinaryData(
        artifact.content,
        artifact.fileName,
        artifact.mimeType
      ),
    },
  };
});

/**
 * n8n Code Node: Final Upload Summary
 *
 * Purpose:
 * Creates one final summary item after all artifacts were uploaded.
 * This avoids repeating the same summary once per uploaded file.
 */

// Read all prepared artifact items from the packaging node.
// This node originally created one item per artifact.
const preparedArtifacts = $('Prepare Artifact Upload Package').all();

// Read the first artifact to get the run folder.
// All artifacts from one run use the same folder.
const firstArtifact = preparedArtifacts[0]?.json ?? {};

// Count how many artifacts were prepared/uploaded.
const uploadedArtifactCount = preparedArtifacts.length;

// Return exactly one summary item.
return [
  {
    json: {
      status: 'Artifact upload completed',
      storageAccount: 'n8ncreativeprompting',
      container: 'ai-generated-artifacts',
      runFolder: firstArtifact.runFolder,
      uploadedArtifactCount: uploadedArtifactCount,
      technicianInstructions:
        'Open the generated run folder in Azure Blob Storage. Start with README.md, then review risk-review.md, inspect Create-EntraUsers-v2.ps1, use users-template.csv, and follow test-checklist.md. Do not execute anything without human review and non-production testing.',
    },
  },
];
